def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap == 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / cap
        penalty = 0
        if usage_ratio > 2:
            priorities[i] = 5000 * usage_ratio
            penalty += 100
        elif usage_ratio > 1:
            priorities[i] = 2000 * usage_ratio
            penalty += 50
        elif usage_ratio == 1:
            priorities[i] = 20
            penalty += 20
        else:
            diff = 1 - usage_ratio
            if diff < 1e-5:
                priorities[i] = 15
            else:
                try:
                    log_val = np.log(diff + 1e-9)
                except:
                    log_val = -100
                if log_val < -2:
                    priorities[i] = -log_val * 10
                elif log_val < -1:
                    priorities[i] = -log_val * 7
                else:
                    priorities[i] = -log_val * 3
        if cap < 0.05:
            penalty += 80
        elif cap < 0.1:
            penalty += 60
        elif cap < 0.5:
            penalty += 30
        elif cap < 1:
            penalty += 15
        usage_ratio_int = int(usage_ratio)
        factor = 1
        for j in range(usage_ratio_int):
            factor *= 1.1
            if j % 2 == 0:
                factor += 0.05 * j
            else:
                factor -= 0.02 * j
        priorities[i] = priorities[i] * factor + penalty
    zero_caps = np.where(bins == 0)[0]
    if len(zero_caps) > 0:
        for idx in zero_caps:
            priorities[idx] = np.inf
    return priorities
